import flatpickr from 'flatpickr';
import 'flatpickr/dist/flatpickr.min.css';

const datetimePicker = document.getElementById('datetime-picker');
const startButton = document.querySelector('[data-start]');
const daysSpan = document.querySelector('[data-days]');
const hoursSpan = document.querySelector('[data-hours]');
const minutesSpan = document.querySelector('[data-minutes]');
const secondsSpan = document.querySelector('[data-seconds]');

let timerInterval = null;
let selectedDate = null;

startButton.disabled = true;

function addLeadingZero(value) {
  return String(value).padStart(2, '0');
}

function convertMs(ms) {
  const second = 1000;
  const minute = second * 60;
  const hour = minute * 60;
  const day = hour * 24;

  const days = Math.floor(ms / day);
  const hours = Math.floor((ms % day) / hour);
  const minutes = Math.floor(((ms % day) % hour) / minute);
  const seconds = Math.floor((((ms % day) % hour) % minute) / second);

  return { days, hours, minutes, seconds };
}

function updateTimerUI({ days, hours, minutes, seconds }) {
  daysSpan.textContent = addLeadingZero(days);
  hoursSpan.textContent = addLeadingZero(hours);
  minutesSpan.textContent = addLeadingZero(minutes);
  secondsSpan.textContent = addLeadingZero(seconds);
}

function stopTimer() {
  if (timerInterval) {
    clearInterval(timerInterval);
    timerInterval = null;
  }
  startButton.disabled = false;
  datetimePicker.disabled = false;
}

function startTimer() {
  if (!selectedDate) return;

  startButton.disabled = true;
  datetimePicker.disabled = true;

  timerInterval = setInterval(() => {
    const now = Date.now();
    const remainingTime = selectedDate - now;

    if (remainingTime <= 0) {
      // Таймер достиг нуля
      stopTimer();
      updateTimerUI({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      return;
    }

    const timeComponents = convertMs(remainingTime);
    updateTimerUI(timeComponents);
  }, 1000);
}

const options = {
  enableTime: true,
  time_24hr: true,
  defaultDate: new Date(),
  minuteIncrement: 1,
  onClose(selectedDates) {
    console.log(selectedDates[0]);

    if (selectedDates[0]) {
      const selectedDateMs = selectedDates[0].getTime();
      const now = Date.now();

      if (selectedDateMs <= now) {
        window.alert('Please choose a date in the future');
        startButton.disabled = true;
        selectedDate = null;
      } else {
        selectedDate = selectedDateMs;
        startButton.disabled = false;
      }
    } else {
      startButton.disabled = true;
      selectedDate = null;
    }
  },
};

flatpickr(datetimePicker, options);

startButton.addEventListener('click', startTimer);

